function openProjectSection(key,project,sections,fixed,rerender){if(!project.id){toast('Save the project before editing its sections.',true);return}const index=fixed.findIndex(x=>x[0]===key),s=sections.find(x=>x.section_key===key)||{project_id:project.id,section_key:key,section_number:index+1,title_en:fixed[index][1],title_zh:fixed[index][2],content_en:{text:''},content_zh:{text:''},layout:'standard',is_visible:true};const modal=document.createElement('div');modal.className='modal-backdrop';modal.innerHTML=`<form class="modal"><div class="modal-head"><h2>${String(index+1).padStart(2,'0')}. ${esc(fixed[index][1])}</h2><button class="close" type="button">×</button></div>${field('English heading','title_en',s.title_en)}${area('English content','content_en',s.content_en?.text||'')}${field('中文标题','title_zh',s.title_zh)}${area('中文内容','content_zh',s.content_zh?.text||'')}${selectField('Layout','layout',s.layout,[['standard','Standard'],['full-width','Full width'],['two-column','Two columns'],['grid','Grid']])}<label class="field"><span><input name="is_visible" type="checkbox" ${s.is_visible?'checked':''}> Visible</span></label><button class="btn btn-primary">Save section</button></form>`;document.body.append(modal);modal.querySelector('.close').onclick=()=>modal.remove();modal.querySelector('form').onsubmit=async e=>{e.preventDefault();const f=new FormData(e.currentTarget),payload={...s,title_en:f.get('title_en'),title_zh:f.get('title_zh'),content_en:{text:f.get('content_en')},content_zh:{text:f.get('content_zh')},layout:f.get('layout'),is_visible:f.get('is_visible')==='on'};if(project._cmsDraftOnly){const old=sections.findIndex(x=>x.section_key===key);old>=0?sections[old]=payload:sections.push(payload);modal.remove();success('Project section staged. Save Draft or Publish to keep it.');return rerender()}delete payload.id;delete payload.created_at;delete payload.updated_at;const{data,error}=await supabase.from('project_sections').upsert(payload,{onConflict:'project_id,section_key'}).select().single();if(error)return toast(error.message,true);const old=sections.findIndex(x=>x.section_key===key);old>=0?sections[old]=data:sections.push(data);modal.remove();toast('Project section saved');rerender()}}

async function media(){loading();const rows=await query('media','*',{order:'created_at',ascending:false,is:{deleted_at:null}});document.querySelector('#content').innerHTML=head('Media Library','Optimized, reusable website images with bilingual alt text.')+`<label class="dropzone"><b>Upload images</b><p>JPG, PNG, WebP or AVIF · maximum 10 MB each · converted to WebP where supported</p><input id="media-upload" type="file" multiple accept="image/jpeg,image/png,image/webp,image/avif"></label><div class="media-grid">${rows.length?rows.map(m=>`<article class="media-card"><img src="${esc(m.public_url)}" alt="${esc(m.alt_en)}" loading="lazy"><div><b>${esc(m.title_en||m.original_name)}</b><small>${Math.round(m.size_bytes/1024)} KB · ${m.width||'?'}×${m.height||'?'}</small><button class="link-button" data-media-delete="${m.id}">Delete</button></div></article>`).join(''):'<div class="empty">No uploaded media yet.</div>'}</div>`;document.querySelector('#media-upload').onchange=e=>uploadMedia([...e.target.files]);document.querySelectorAll('[data-media-delete]').forEach(b=>b.onclick=()=>deleteMedia(rows.find(x=>x.id===b.dataset.mediaDelete)))}
async function optimizeImage(file){if(file.type==='image/avif'||file.type==='image/webp')return{blob:file,width:0,height:0};const bitmap=await createImageBitmap(file);const scale=Math.min(1,2560/Math.max(bitmap.width,bitmap.height));const canvas=document.createElement('canvas');canvas.width=Math.round(bitmap.width*scale);canvas.height=Math.round(bitmap.height*scale);canvas.getContext('2d').drawImage(bitmap,0,0,canvas.width,canvas.height);const blob=await new Promise(resolve=>canvas.toBlob(resolve,'image/webp',.86));bitmap.close();return{blob:blob||file,width:canvas.width,height:canvas.height}}
async function uploadMedia(files){const allowed=new Set(['image/jpeg','image/png','image/webp','image/avif']);for(const file of files){if(!allowed.has(file.type)||file.size>10485760){toast(`${file.name}: unsupported type or larger than 10 MB`,true);continue}try{toast(`Optimizing ${file.name}…`);const output=await optimizeImage(file),extension=output.blob.type==='image/webp'?'webp':file.name.split('.').pop().toLowerCase(),name=`${state.profile.user_id}/${Date.now()}-${crypto.randomUUID()}.${extension}`;const{error}=await supabase.storage.from('cms-media').upload(name,output.blob,{contentType:output.blob.type,cacheControl:'31536000',upsert:false});if(error)throw error;const{data:url}=supabase.storage.from('cms-media').getPublicUrl(name);const{error:dbError}=await supabase.from('media').insert({object_path:name,public_url:url.publicUrl,original_name:file.name,mime_type:output.blob.type,size_bytes:output.blob.size,width:output.width||null,height:output.height||null,uploaded_by:state.profile.user_id});if(dbError){await supabase.storage.from('cms-media').remove([name]);throw dbError}toast(`${file.name} uploaded`)}catch(error){toast(error.message,true)}}media()}
async function deleteMedia(item){const [servicesUse,coverUse,shareUse,projectUse]=await Promise.all([query('services','id,title_en',{eq:{cover_media_id:item.id}}),query('projects','id,title_en',{eq:{cover_media_id:item.id}}),query('projects','id,title_en',{eq:{share_media_id:item.id}}),query('project_media','project_id',{eq:{media_id:item.id}})]);const count=servicesUse.length+coverUse.length+shareUse.length+projectUse.length;if(!confirm(`Move this image to the Recycle Bin?${count?` It is used in ${count} place(s) and will disappear from those pages until restored.`:''}`))return;const{error}=await supabase.from('media').update({deleted_at:new Date().toISOString()}).eq('id',item.id);if(error)return toast(error.message,true);success('Image removed from the website and moved to the Recycle Bin.');friendlyMedia()}

