function bindProjectGallery(project,gallery,rerender){
  const list=document.querySelector('[data-gallery-list]'),upload=document.querySelector('[data-gallery-upload]');if(!list||!upload)return;
  list.querySelectorAll('[data-gallery-index]').forEach(card=>{const index=Number(card.dataset.galleryIndex),caption=card.querySelector(`[name="gallery-caption-${index}"]`),section=card.querySelector(`[data-gallery-section="${index}"]`);if(caption)caption.oninput=()=>gallery[index][`caption_${state.lang}`]=caption.value;if(section)section.onchange=()=>gallery[index].section_key=section.value});
  list.querySelectorAll('[data-gallery-remove]').forEach(button=>button.onclick=()=>{if(!confirm('Remove this image from the project page? It remains safely in Media Library.'))return;gallery.splice(Number(button.dataset.galleryRemove),1);success('Image removed from this project. Publish to update the website.');rerender()});
  upload.onchange=async event=>{for(const file of [...event.target.files]){try{const media=await uploadAsset(file);gallery.push({project_id:project.id||null,media_id:media.id,section_key:'showcase',caption_en:'',caption_zh:'',layout:'standard',sort_order:gallery.length,media});success(`${file.name} added to the project gallery.`)}catch(error){toast(error.message,true)}}rerender()};
  let dragged=null;list.querySelectorAll('[data-gallery-index]').forEach(card=>{card.ondragstart=()=>{dragged=Number(card.dataset.galleryIndex);card.classList.add('dragging')};card.ondragend=()=>card.classList.remove('dragging');card.ondragover=event=>event.preventDefault();card.ondrop=event=>{event.preventDefault();const target=Number(card.dataset.galleryIndex);if(dragged===null||dragged===target)return;const [item]=gallery.splice(dragged,1);gallery.splice(target,0,item);gallery.forEach((value,index)=>value.sort_order=index);success('Project image order updated. Publish to update the website.');rerender()}});
}

