  const upload=async files=>{for(const file of files){try{toast(`Uploading ${file.name}…`);await uploadAsset(file);success(`${file.name} uploaded successfully.`)}catch(error){toast(error.message,true)}}friendlyMedia()};const input=document.querySelector('#media-upload'),drop=document.querySelector('#friendly-dropzone');input.onchange=()=>upload([...input.files]);drop.ondragover=event=>{event.preventDefault();drop.classList.add('drag-over')};drop.ondragleave=()=>drop.classList.remove('drag-over');drop.ondrop=event=>{event.preventDefault();drop.classList.remove('drag-over');upload([...event.dataTransfer.files])};
