async function openFriendlyMediaEditor(item){const [serviceUse,coverUse,shareUse,galleryUse]=await Promise.all([query('services','id,title_en',{eq:{cover_media_id:item.id}}),query('projects','id,title_en',{eq:{cover_media_id:item.id}}),query('projects','id,title_en',{eq:{share_media_id:item.id}}),query('project_media','project_id',{eq:{media_id:item.id}})]),uses=[...serviceUse.map(row=>`Service: ${row.title_en}`),...coverUse.map(row=>`Project cover: ${row.title_en}`),...shareUse.map(row=>`Project sharing image: ${row.title_en}`),...galleryUse.map(row=>`Project gallery: ${row.project_id}`)];const modal=document.createElement('div');modal.className='modal-backdrop';const render=()=>{const lang=state.lang;modal.innerHTML=`<form class="modal media-editor-modal"><div class="modal-head"><h2>Edit image</h2><button class="close" type="button">×</button></div><div class="crop-preview"><img src="${esc(item.public_url)}" alt="" style="object-position:${Number(item.focal_x||.5)*100}% ${Number(item.focal_y||.5)*100}%"></div><div class="media-facts"><span>${item.width||'?'} × ${item.height||'?'} px</span><span>${Math.round(item.size_bytes/1024)} KB</span><span>Used in ${uses.length} place(s)</span></div>${languageTabs()}${field('Image title',`title_${lang}`,item[`title_${lang}`]||'')}${area('Alternative text',`alt_${lang}`,item[`alt_${lang}`]||'')}<div class="grid-2"><label class="field"><span>Crop focus — horizontal</span><input type="range" name="focal_x" min="0" max="1" step="0.01" value="${item.focal_x||.5}"></label><label class="field"><span>Crop focus — vertical</span><input type="range" name="focal_y" min="0" max="1" step="0.01" value="${item.focal_y||.5}"></label></div><section class="usage-box"><b>Where this image is used</b>${uses.length?`<ul>${uses.map(value=>`<li>${esc(value)}</li>`).join('')}</ul>`:'<p>Not currently used on the website.</p>'}</section><div class="workflow-bar"><button class="btn btn-primary" type="submit">Update Image</button><label class="btn">Replace / Resize<input type="file" hidden data-modal-replace accept="image/jpeg,image/png,image/webp,image/avif"></label><button class="btn" type="button" data-cancel>Cancel</button></div></form>`;const form=modal.querySelector('form'),preview=modal.querySelector('.crop-preview img'),capture=()=>{const data=new FormData(form);item[`title_${lang}`]=data.get(`title_${lang}`);item[`alt_${lang}`]=data.get(`alt_${lang}`);item.focal_x=Number(data.get('focal_x'));item.focal_y=Number(data.get('focal_y'))};form.querySelectorAll('input[type=range]').forEach(input=>input.oninput=()=>{capture();preview.style.objectPosition=`${item.focal_x*100}% ${item.focal_y*100}%`});modal.querySelector('.close').onclick=()=>modal.remove();modal.querySelector('[data-cancel]').onclick=()=>modal.remove();modal.querySelectorAll('[data-lang]').forEach(button=>button.onclick=()=>{capture();state.lang=button.dataset.lang;render()});modal.querySelector('[data-modal-replace]').onchange=async event=>{modal.remove();await replaceFriendlyMedia(item,event.target.files[0])};form.onsubmit=async event=>{event.preventDefault();capture();const{error}=await supabase.from('media').update({title_en:item.title_en,title_zh:item.title_zh,alt_en:item.alt_en,alt_zh:item.alt_zh,focal_x:item.focal_x,focal_y:item.focal_y}).eq('id',item.id);if(error)return toast(error.message,true);modal.remove();success('Image updated everywhere it is used.');friendlyMedia()}};document.body.append(modal);render()}
async function replaceFriendlyMedia(item,file){try{const replacement=await uploadAsset(file);const{error:removeTempError}=await supabase.from('media').delete().eq('id',replacement.id);if(removeTempError)throw removeTempError;const payload={object_path:replacement.object_path,public_url:replacement.public_url,original_name:replacement.original_name,mime_type:replacement.mime_type,size_bytes:replacement.size_bytes,width:replacement.width,height:replacement.height};const{error}=await supabase.from('media').update(payload).eq('id',item.id);if(error)throw error;success('Image replaced everywhere it is used. The previous version remains available in Version History.');friendlyMedia()}catch(error){toast(error.message,true)}}

