const visualSchema = window.INFINITY_VISUAL_SCHEMA || [];
const clone = value => JSON.parse(JSON.stringify(value));
function schemaFor(section){const key=section.layout?.clone_of||section.section_key;return visualSchema.find(item=>item.key===key)||visualSchema[0]}
function defaultFields(schema,lang){return Object.fromEntries(schema.fields.map(item=>[item.key,item[lang]||item.en||'']))}
function mergeVisualSection(schema,record,pageId,index){
  const row=record?clone(record):{page_id:pageId,section_key:schema.key,section_type:schema.key==='home'?'hero':'text',title_en:schema.label,title_zh:schema.label,content_en:{},content_zh:{},layout:{},is_visible:true,sort_order:index};
  for(const lang of ['en','zh']){const current=row[`content_${lang}`]||{},fields={...defaultFields(schema,lang),...(current.fields||{})};if(!current.fields){if(row[`title_${lang}`])fields.titleLine1=row[`title_${lang}`];if(current.text){const legacyKey=schema.key==='home'?'eyebrow':schema.key==='contact'?'description':schema.key==='portfolio'?'intro':schema.key==='about'?'lead':'intro';if(fields[legacyKey]!==undefined)fields[legacyKey]=current.text}}row[`content_${lang}`]={...current,fields}}
  row.layout=row.layout||{};row.sort_order=Number.isFinite(row.sort_order)?row.sort_order:index;return row;
}
function visualHowTo(label){return `<aside class="how-to"><div class="how-to-icon">?</div><div><p class="eyebrow">How to use this page</p><h2>Edit the real ${esc(label)} visually</h2><p>Choose English or Chinese, type in the normal fields and watch the website preview update immediately. Save Draft keeps work private. Update Website publishes it.</p><div class="guide-chips"><span><b>Edit</b> change text</span><span><b>Preview</b> review instantly</span><span><b>Update Website</b> publish live</span></div></div></aside>`}
function previewMessage(frame,sections,lang){if(!frame?.contentWindow)return;frame.contentWindow.postMessage({type:'infinity-cms-preview',lang,sections:sections.map(section=>({section_key:section.section_key,is_visible:section.is_visible,sort_order:section.sort_order,layout:section.layout||{},content:section[`content_${lang}`]||{}}))},location.origin)}

async function visualPageEditor(route='home'){
  loading();let homePage=(await query('pages','*',{eq:{slug:'home'},is:{deleted_at:null}}))[0];if(!homePage){const{data,error}=await supabase.from('pages').insert({slug:'home',title_en:'Home',title_zh:'首页',description_en:'INfinity Design Studio',description_zh:'INfinity 设计工作室',status:'published',published_at:new Date().toISOString(),created_by:state.profile.user_id,updated_by:state.profile.user_id}).select().single();if(error)throw error;homePage=data}
  const records=await query('page_sections','*',{eq:{page_id:homePage.id},order:'sort_order'}),recordMap=new Map(records.map(item=>[item.section_key,item]));
  const filter=route==='about'?['about']:route==='contact'?['contact']:visualSchema.map(item=>item.key);let sections=filter.map((key,index)=>{const schema=visualSchema.find(item=>item.key===key);return mergeVisualSection(schema,recordMap.get(key),homePage.id,index)});
  const duplicateRecords=records.filter(item=>item.layout?.clone_of&&filter.includes(item.layout.clone_of)).map(item=>mergeVisualSection(schemaFor(item),item,homePage.id,item.sort_order));sections.push(...duplicateRecords);sections.sort((a,b)=>a.sort_order-b.sort_order);
  const draftKey=`visual-draft-${route}`,draft=JSON.parse(localStorage.getItem(draftKey)||'null');if(draft?.sections)sections=draft.sections;
  let lang=state.lang,history=[clone(sections)],historyIndex=0,expanded=sections.find(item=>item.is_visible)?.section_key||sections[0]?.section_key,historyTimer;
  const pushHistory=()=>{clearTimeout(historyTimer);history=history.slice(0,historyIndex+1);history.push(clone(sections));historyIndex=history.length-1;const undo=document.querySelector('[data-undo]'),redo=document.querySelector('[data-redo]');if(undo)undo.disabled=historyIndex<=0;if(redo)redo.disabled=historyIndex>=history.length-1};
  const scheduleHistory=()=>{clearTimeout(historyTimer);historyTimer=setTimeout(pushHistory,450)};
  const change=(mutator,rerender=true)=>{mutator();sections.forEach((item,index)=>item.sort_order=index);pushHistory();if(rerender)render()};
  const render=()=>{
    const pageLabel=route==='home'?'Home Page':route==='about'?'About Section':'Contact Section',visible=sections.filter(item=>!item.layout?.deleted_at);
    document.querySelector('#content').innerHTML=head(pageLabel,'The editor below mirrors the real public website.')+visualHowTo(pageLabel)+`<div class="visual-toolbar"><button class="btn" data-visual-draft>Save Draft</button><a class="btn" href="${publicUrl}/" target="_blank" rel="noopener">Preview in New Tab</a><button class="btn btn-primary" data-visual-publish>Update Website</button><span class="toolbar-divider"></span><button class="btn" data-undo ${historyIndex<=0?'disabled':''}>Undo</button><button class="btn" data-redo ${historyIndex>=history.length-1?'disabled':''}>Redo</button><button class="btn" data-restore>Restore</button><span class="save-status" data-save-status></span></div><div class="visual-workspace"><div class="visual-editor">${visible.map((section,index)=>visualSectionCard(section,index,lang,expanded===section.section_key,visible.length)).join('')||'<div class="empty">All sections are in the Recycle Bin. Select Restore to bring one back.</div>'}</div><aside class="preview-panel"><div class="preview-head"><div><b>Live Preview</b><small>Updates as you type</small></div><span>${lang==='en'?'English':'简体中文'}</span></div><iframe id="visual-preview" title="Live website preview" src="${publicUrl}/?cms-preview=1#${route==='home'?'home':route}"></iframe></aside></div>`;
    const frame=document.querySelector('#visual-preview');frame.onload=()=>previewMessage(frame,sections,lang);
    document.querySelectorAll('[data-visual-lang]').forEach(button=>button.onclick=()=>{lang=button.dataset.visualLang;state.lang=lang;render()});
    document.querySelectorAll('[data-section-toggle]').forEach(button=>button.onclick=()=>{expanded=expanded===button.dataset.sectionToggle?'':button.dataset.sectionToggle;render()});
    document.querySelectorAll('[data-visual-field]').forEach(input=>{input.oninput=()=>{const section=sections.find(item=>item.section_key===input.dataset.sectionKey);section[`content_${lang}`].fields[input.dataset.visualField]=input.value;previewMessage(frame,sections,lang);scheduleHistory()}});
    document.querySelectorAll('[data-visible]').forEach(input=>input.onchange=()=>change(()=>{sections.find(item=>item.section_key===input.dataset.visible).is_visible=input.checked}));
    document.querySelectorAll('[data-move-up]').forEach(button=>button.onclick=()=>change(()=>{const index=sections.findIndex(item=>item.section_key===button.dataset.moveUp);if(index>0)[sections[index-1],sections[index]]=[sections[index],sections[index-1]]}));
    document.querySelectorAll('[data-move-down]').forEach(button=>button.onclick=()=>change(()=>{const index=sections.findIndex(item=>item.section_key===button.dataset.moveDown);if(index<sections.length-1)[sections[index],sections[index+1]]=[sections[index+1],sections[index]]}));
    document.querySelectorAll('[data-duplicate]').forEach(button=>button.onclick=()=>change(()=>{const source=sections.find(item=>item.section_key===button.dataset.duplicate),copy=clone(source);delete copy.id;copy.section_key=`${source.layout?.clone_of||source.section_key}-copy-${Date.now()}`;copy.layout={...(copy.layout||{}),clone_of:source.layout?.clone_of||source.section_key};copy.title_en=`${source.title_en} Copy`;copy.title_zh=`${source.title_zh} 副本`;sections.splice(sections.indexOf(source)+1,0,copy);expanded=copy.section_key}));
    document.querySelectorAll('[data-delete-section]').forEach(button=>button.onclick=()=>{if(!confirm('Move this section to the Recycle Bin? You can restore it later.'))return;change(()=>{const section=sections.find(item=>item.section_key===button.dataset.deleteSection);section.is_visible=false;section.layout={...(section.layout||{}),deleted_at:new Date().toISOString()}})});
    document.querySelector('[data-undo]').onclick=()=>{if(historyIndex<=0)return;sections=clone(history[--historyIndex]);render()};document.querySelector('[data-redo]').onclick=()=>{if(historyIndex>=history.length-1)return;sections=clone(history[++historyIndex]);render()};
    document.querySelector('[data-restore]').onclick=()=>navigate('recycle');
    document.querySelector('[data-visual-draft]').onclick=()=>{localStorage.setItem(draftKey,JSON.stringify({sections,saved_at:new Date().toISOString()}));success('Draft saved privately. The public website has not changed.')};
    document.querySelector('[data-visual-publish]').onclick=async()=>{const button=document.querySelector('[data-visual-publish]');button.disabled=true;button.textContent='Updating…';try{for(const section of sections){const payload={page_id:homePage.id,section_key:section.section_key,section_type:section.section_type,title_en:section.title_en,title_zh:section.title_zh,content_en:section.content_en,content_zh:section.content_zh,layout:section.layout||{},is_visible:section.is_visible,sort_order:section.sort_order};const{error}=await supabase.from('page_sections').upsert(payload,{onConflict:'page_id,section_key'});if(error)throw error}await supabase.from('pages').update({status:'published',published_at:new Date().toISOString(),updated_by:state.profile.user_id}).eq('id',homePage.id);localStorage.removeItem(draftKey);success('Website updated successfully. The public page now uses this content.');frame.src=`${publicUrl}/?published=${Date.now()}#${route==='home'?'home':route}`}catch(error){toast(error.message,true)}finally{button.disabled=false;button.textContent='Update Website'}};
  };render();
}
function visualSectionCard(section,index,lang,isOpen,total){const schema=schemaFor(section),fields=section[`content_${lang}`]?.fields||defaultFields(schema,lang);return `<article class="visual-section-card ${isOpen?'open':''}" draggable="true" data-visual-section="${esc(section.section_key)}"><header><button class="section-summary" type="button" data-section-toggle="${esc(section.section_key)}"><span class="section-icon">${esc(schema.icon)}</span><span><b>${esc(schema.label)}${section.layout?.clone_of?' (Copy)':''}</b><small>${esc(schema.description)}</small></span><i>${isOpen?'−':'+'}</i></button><label class="visual-switch" title="Show or hide this section on the website"><input type="checkbox" data-visible="${esc(section.section_key)}" ${section.is_visible?'checked':''}><span></span><b>${section.is_visible?'Visible':'Hidden'}</b></label></header>${isOpen?`<div class="visual-section-body"><div class="visual-language-tabs" role="tablist"><button class="${lang==='en'?'active':''}" type="button" data-visual-lang="en">English</button><button class="${lang==='zh'?'active':''}" type="button" data-visual-lang="zh">简体中文</button></div><div class="visual-fields">${schema.fields.map(item=>item.type==='textarea'?`<label><span>${esc(item.label)} <i title="${esc(`Changes ${item.label.toLowerCase()} in the ${schema.label}.`)}">?</i></span><textarea data-section-key="${esc(section.section_key)}" data-visual-field="${esc(item.key)}">${esc(fields[item.key]||'')}</textarea></label>`:`<label><span>${esc(item.label)} <i title="${esc(`Changes ${item.label.toLowerCase()} in the ${schema.label}.`)}">?</i></span><input type="${item.type==='url'?'text':'text'}" data-section-key="${esc(section.section_key)}" data-visual-field="${esc(item.key)}" value="${esc(fields[item.key]||'')}"></label>`).join('')}</div><div class="section-controls"><button class="btn" type="button" data-move-up="${esc(section.section_key)}" ${index===0?'disabled':''}>Move Up</button><button class="btn" type="button" data-move-down="${esc(section.section_key)}" ${index===total-1?'disabled':''}>Move Down</button><button class="btn" type="button" data-duplicate="${esc(section.section_key)}">Duplicate Section</button><button class="btn danger" type="button" data-delete-section="${esc(section.section_key)}">Delete Section</button></div></div>`:''}</article>`}

async function recycleBin(){
  loading();const [sections,mediaRows,projectsRows,servicesRows,pagesRows]=await Promise.all([query('page_sections','*',{order:'updated_at',ascending:false}),query('media','*',{order:'created_at',ascending:false}),query('projects','*',{order:'updated_at',ascending:false}),query('services','*',{order:'updated_at',ascending:false}),query('pages','*',{order:'updated_at',ascending:false})]);const items=[...sections.filter(item=>item.layout?.deleted_at).map(item=>({type:'Section',table:'page_sections',row:item,label:item.title_en||item.section_key})),...mediaRows.filter(item=>item.deleted_at).map(item=>({type:'Image',table:'media',row:item,label:item.title_en||item.original_name})),...projectsRows.filter(item=>item.deleted_at).map(item=>({type:'Project',table:'projects',row:item,label:item.title_en})),...servicesRows.filter(item=>item.deleted_at).map(item=>({type:'Service',table:'services',row:item,label:item.title_en})),...pagesRows.filter(item=>item.deleted_at).map(item=>({type:'Page',table:'pages',row:item,label:item.title_en}))];document.querySelector('#content').innerHTML=head('Recycle Bin','Deleted content stays recoverable. Restore it whenever you need.')+`<div class="how-to"><div class="how-to-icon">↶</div><div><h2>Nothing is permanently deleted here</h2><p>Restore returns the item to the CMS. Publish its page when you want it visible on the public website again.</p></div></div><div class="records">${items.map((item,index)=>`<article class="record-card"><div class="record-main"><b>${esc(item.label)}</b><small>${esc(item.type)} · deleted ${new Date(item.row.layout?.deleted_at||item.row.deleted_at).toLocaleString()}</small></div><button class="btn btn-primary" data-recycle-restore="${index}">Restore</button></article>`).join('')||'<div class="empty"><b>Recycle Bin is empty</b><p>Deleted sections, services, projects, pages and images will appear here.</p></div>'}</div>`;document.querySelectorAll('[data-recycle-restore]').forEach(button=>button.onclick=async()=>{const item=items[Number(button.dataset.recycleRestore)];let payload;if(item.table==='page_sections'){const layout={...(item.row.layout||{})};delete layout.deleted_at;payload={layout,is_visible:true}}else if(item.table==='services')payload={deleted_at:null,is_visible:true};else if(item.table==='projects')payload={deleted_at:null,status:'draft'};else payload={deleted_at:null};const{error}=await supabase.from(item.table).update(payload).eq('id',item.row.id);if(error)return toast(error.message,true);success(`${item.type} restored.`);recycleBin()})
}
async function versionHistory(){
  if(state.profile.role!=='owner')return document.querySelector('#content').innerHTML=head('Version History','Owner access is required.')+'<div class="empty">Editors can use Undo while editing, but only Owner can restore database versions.</div>';
  loading();const [versions,logs]=await Promise.all([query('content_versions','id,entity_table,entity_id,operation,before_data,after_data,created_at,admin_users(display_name)',{order:'created_at',ascending:false}),query('activity_logs','id,action,entity_table,created_at,admin_users(display_name)',{order:'created_at',ascending:false})]);document.querySelector('#content').innerHTML=head('Version History','See who changed content, when it changed and restore an earlier version.')+`<div class="how-to"><div class="how-to-icon">↶</div><div><h2>Restore a previous version safely</h2><p>Choose Restore Previous Version. The restoration itself is recorded, so you can reverse it again if needed.</p></div></div><div class="grid-2"><section class="panel"><h2>Restorable versions</h2><div class="records">${versions.slice(0,100).map(version=>`<article class="record-card"><div class="record-main"><b>${esc(version.entity_table.replaceAll('_',' '))} · ${esc(version.operation)}</b><small>${new Date(version.created_at).toLocaleString()} · ${esc(version.admin_users?.display_name||'Administrator')}</small></div>${version.before_data&&version.entity_table!=='admin_users'?`<button class="btn" data-version-restore="${version.id}">Restore Previous Version</button>`:''}</article>`).join('')||'<div class="empty">No previous versions yet.</div>'}</div></section><section class="panel"><h2>Activity</h2>${logs.slice(0,100).map(log=>`<div class="log"><time>${new Date(log.created_at).toLocaleString()}</time><span>${esc(log.admin_users?.display_name||'System')}</span><b>${esc(log.action)} · ${esc(log.entity_table||'authentication')}</b></div>`).join('')||'<div class="empty">No activity yet.</div>'}</section></div>`;document.querySelectorAll('[data-version-restore]').forEach(button=>button.onclick=async()=>{const version=versions.find(item=>String(item.id)===button.dataset.versionRestore);if(!version||!confirm('Restore this previous version? The current state will remain in Version History.'))return;const payload=clone(version.before_data);try{let request;if(version.operation==='delete')request=supabase.from(version.entity_table).upsert(payload,{onConflict:'id'});else{delete payload.id;delete payload.created_at;delete payload.updated_at;request=supabase.from(version.entity_table).update(payload).eq('id',version.entity_id)}const{error}=await request;if(error)throw error;success('Previous version restored. Publish or refresh the related page to verify it.');versionHistory()}catch(error){toast(error.message,true)}})
}
async function friendlyNavigation(){
  loading();let rows=await query('navigation_items','*',{order:'sort_order'});document.querySelector('#content').innerHTML=head('Navigation','These links match the public desktop and mobile menus.',`<button class="btn btn-primary" data-new-nav>+ Add menu item</button>`)+`<div class="how-to"><div class="how-to-icon">↕</div><div><h2>Drag links into the order you want</h2><p>Click Edit to change normal English and Chinese labels. Hidden links disappear after Update.</p></div></div><div class="records" id="navigation-sort-list">${rows.map(row=>`<article class="record-card" draggable="true" data-section="${row.id}"><span class="drag-handle">⋮⋮</span><div class="record-main"><b>${esc(row.label_en)} / ${esc(row.label_zh)}</b><small>${esc(row.url)} · ${row.is_visible?'Visible':'Hidden'} · ${row.mobile_visible?'Mobile':'Desktop only'}</small></div><button class="btn" data-edit-nav="${row.id}">Edit</button></article>`).join('')||'<div class="empty">No menu links yet.</div>'}</div>`;
  const open=row=>{let item=row||{label_en:'',label_zh:'',url:'/',is_visible:true,mobile_visible:true,sort_order:rows.length},lang='en';const render=()=>{modal(item.id?'Edit menu item':'Add menu item',`${languageTabs()}${field('Menu label',`label_${lang}`,item[`label_${lang}`]||'')}${field('Link destination','url',item.url||'/')}<label class="field checkbox-field"><span><input name="is_visible" type="checkbox" ${item.is_visible?'checked':''}> Visible on website</span></label><label class="field checkbox-field"><span><input name="mobile_visible" type="checkbox" ${item.mobile_visible?'checked':''}> Show on mobile</span></label>`,{label:'Update Navigation',class:'btn-primary',onClick:save});const form=document.querySelector('#modal-form'),capture=()=>{item[`label_${lang}`]=form.elements[`label_${lang}`].value;item.url=form.elements.url.value;item.is_visible=form.elements.is_visible.checked;item.mobile_visible=form.elements.mobile_visible.checked};document.querySelectorAll('[data-lang]').forEach(button=>button.onclick=()=>{capture();lang=button.dataset.lang;state.lang=lang;render()})};async function save(){const form=document.querySelector('#modal-form');item[`label_${lang}`]=form.elements[`label_${lang}`].value;item.url=form.elements.url.value;item.is_visible=form.elements.is_visible.checked;item.mobile_visible=form.elements.mobile_visible.checked;if(!/^(\/|#|https:\/\/)/.test(item.url))return toast('Link must start with /, # or https://',true);const payload={label_en:item.label_en||'Menu item',label_zh:item.label_zh||item.label_en||'菜单',url:item.url,target:'_self',is_visible:item.is_visible,mobile_visible:item.mobile_visible,sort_order:item.sort_order};const request=item.id?supabase.from('navigation_items').update(payload).eq('id',item.id):supabase.from('navigation_items').insert(payload);const{error}=await request;if(error)return toast(error.message,true);closeModal();success('Navigation updated on the live website.');friendlyNavigation()}render()};
  document.querySelector('[data-new-nav]').onclick=()=>open();document.querySelectorAll('[data-edit-nav]').forEach(button=>button.onclick=()=>open(rows.find(row=>row.id===button.dataset.editNav)));bindDragList(document.querySelector('#navigation-sort-list'),async ids=>{for(let index=0;index<ids.length;index++){const{error}=await supabase.from('navigation_items').update({sort_order:index}).eq('id',ids[index]);if(error)return toast(error.message,true)}success('Navigation order updated on the website.')});
}
function guide(){document.querySelector('#content').innerHTML=head('Help & Guide','A beginner-friendly tutorial for managing the website without code.')+`<div class="guide-grid"><section class="panel guide-steps"><h2>Update website content</h2><ol><li><b>Choose Home, About or Contact.</b><span>Each card is a real section from the public website.</span></li><li><b>Choose a language.</b><span>Edit English and 简体中文 in normal text fields.</span></li><li><b>Watch Live Preview.</b><span>The preview changes immediately while you type.</span></li><li><b>Save Draft.</b><span>Keep unfinished work private on this device.</span></li><li><b>Update Website.</b><span>Publish the edited content to visitors immediately.</span></li><li><b>Use Undo or Redo.</b><span>Reverse typing, sorting, duplication, visibility and deletion before publishing.</span></li></ol></section><section class="panel"><h2>Images</h2><p>Media Library supports multiple upload, replacement, crop focus, bilingual alt text, usage information and recoverable deletion. JPG and PNG uploads are optimized to WebP.</p><h2>Sorting</h2><p>Drag Services, Projects, Images and Navigation into the order you want. Page sections also include Move Up and Move Down controls.</p><h2>Recover mistakes</h2><p>Recycle Bin restores deleted sections, pages, projects and images. Owner can use Version History to see who changed an item, when it changed and restore an earlier database version.</p><h2>What each button does</h2><p><b>Save Draft</b> keeps private work. <b>Preview</b> opens the website. <b>Update Website</b> publishes. <b>Undo/Redo</b> reverses local edits. <b>Restore</b> opens recoverable content.</p></section></div>`}

async function renderRoute(){parseRoute();document.querySelectorAll('[data-route]').forEach(a=>a.classList.toggle('active',a.dataset.route===state.route));const label=document.querySelector('.topbar .eyebrow');if(label)label.textContent=titles[state.route];try{if(state.route==='dashboard')await dashboard();else if(['home','about','contact'].includes(state.route))await visualPageEditor(state.route);else if(state.route==='pages')await friendlyPages('pages');else if(state.route==='services')await friendlyServices();else if(state.route==='projects')await friendlyProjects();else if(state.route==='media')await friendlyMedia();else if(['theme','footer','settings','navigation','seo'].includes(state.route))await simpleSettings(state.route);else if(state.route==='users')await users();else if(state.route==='activity')await versionHistory();else if(state.route==='recycle')await recycleBin();else if(state.route==='languages')languages();else if(state.route==='guide')guide()}catch(error){console.error(error);document.querySelector('#content').innerHTML=head('Unable to load','The CMS received a database error.')+`<div class="danger-note">${esc(error.message)}</div>`}}

async function start(){if(!configured)return setupView();const {data}=await supabase.auth.getSession();state.session=data.session;if(!state.session)return authView();if(!await loadProfile())return authView();parseRoute();shell()}
window.addEventListener('hashchange',()=>{if(state.session)renderRoute()});
if(supabase)supabase.auth.onAuthStateChange(async(event,session)=>{state.session=session;if(event==='SIGNED_OUT'){state.profile=null;authView()}else if(event==='SIGNED_IN'&&!state.profile){if(await loadProfile()){parseRoute();shell()}}});
start();
